leg查看程序源码，需要计算出三个正确的 key 值才能得到 flag 信息。
#include &lt;stdio.h&gt;#include &lt;fcntl.h&gt;int key1()&#123;	asm(&quot;mov r3, pc\n&quot;);&#125;int key2()&#123;	asm(	&quot;push	&#123;r6&#125;\n&quot;	&quot;add	r6, pc, $1\n&quot;	&quot;bx	r6\n&quot;	&quot;.code   16\n&quot;	&quot;mov	r3, pc\n&quot;	&quot;add	r3, $0x4\n&quot;	&quot;push	&#123;r3&#125;\n&quot;	&quot;pop	&#123;pc&#125;\n&quot;	&quot;.code	32\n&quot;	&quot;pop	&#123;r6&#125;\n&quot;	);&#125;int key3()&#123;	asm(&quot;mov r3, lr\n&quot;);&#125;int main()&#123;	int key=0;	printf(&quot;Daddy has very strong arm! : &quot;);	scanf(&quot;%d&quot;, &amp;key);	if( (key1()+key2()+key3()) == key )&#123;		printf(&quot;Congratz!\n&quot;);		int fd = open(&quot;flag&quot;, O_RDONLY);		char buf[100];		int r = read(fd, buf, 100);		write(0, buf, r);	&#125;	else&#123;		printf(&quot;I have strong leg :P\n&quot;);	&#125;	return 0;&#125;

根据题目给出的调试信息，分析三个 key 函数的返回值。
查看 key1() 函数的汇编代码。
(gdb) disass key1Dump of assembler code for function key1:   0x00008cd4 &lt;+0&gt;:	push	&#123;r11&#125;		; (str r11, [sp, #-4]!)   0x00008cd8 &lt;+4&gt;:	add	r11, sp, #0   0x00008cdc &lt;+8&gt;:	mov	r3, pc   0x00008ce0 &lt;+12&gt;:	mov	r0, r3   0x00008ce4 &lt;+16&gt;:	sub	sp, r11, #0   0x00008ce8 &lt;+20&gt;:	pop	&#123;r11&#125;		; (ldr r11, [sp], #4)   0x00008cec &lt;+24&gt;:	bx	lrEnd of assembler dump.

根据 Arm 架构的三级流水线特性，当 0x00008cdc 处的指令执行时，寄存器 pc 中的值为 0x00008ce4，所以 key1() 函数的返回值为 0x00008ce4。
查看 key2() 函数的汇编代码。
(gdb) disass key2Dump of assembler code for function key2:   0x00008cf0 &lt;+0&gt;:	push	&#123;r11&#125;		; (str r11, [sp, #-4]!)   0x00008cf4 &lt;+4&gt;:	add	r11, sp, #0   0x00008cf8 &lt;+8&gt;:	push	&#123;r6&#125;		; (str r6, [sp, #-4]!)   0x00008cfc &lt;+12&gt;:	add	r6, pc, #1   0x00008d00 &lt;+16&gt;:	bx	r6   0x00008d04 &lt;+20&gt;:	mov	r3, pc   0x00008d06 &lt;+22&gt;:	adds	r3, #4   0x00008d08 &lt;+24&gt;:	push	&#123;r3&#125;   0x00008d0a &lt;+26&gt;:	pop	&#123;pc&#125;   0x00008d0c &lt;+28&gt;:	pop	&#123;r6&#125;		; (ldr r6, [sp], #4)   0x00008d10 &lt;+32&gt;:	mov	r0, r3   0x00008d14 &lt;+36&gt;:	sub	sp, r11, #0   0x00008d18 &lt;+40&gt;:	pop	&#123;r11&#125;		; (ldr r11, [sp], #4)   0x00008d1c &lt;+44&gt;:	bx	lrEnd of assembler dump.

根据 Arm 架构的状态变换特性，当 0x00008d04 处指令执行时，寄存器 pc 的值为 0x00008d04，因此 key2() 函数的返回值为 0x00008d0c。
查看 main() 和 key3() 函数的汇编代码。
(gdb) disass mainDump of assembler code for function main:   ....   0x00008d7c &lt;+64&gt;:	bl	0x8d20 &lt;key3&gt;   0x00008d80 &lt;+68&gt;:	mov	r3, r0   0x00008d84 &lt;+72&gt;:	add	r2, r4, r3   0x00008d88 &lt;+76&gt;:	ldr	r3, [r11, #-16]   ....End of assembler dump.

(gdb) disass key3Dump of assembler code for function key3:   0x00008d20 &lt;+0&gt;:	push	&#123;r11&#125;		; (str r11, [sp, #-4]!)   0x00008d24 &lt;+4&gt;:	add	r11, sp, #0   0x00008d28 &lt;+8&gt;:	mov	r3, lr   0x00008d2c &lt;+12&gt;:	mov	r0, r3   0x00008d30 &lt;+16&gt;:	sub	sp, r11, #0   0x00008d34 &lt;+20&gt;:	pop	&#123;r11&#125;		; (ldr r11, [sp], #4)   0x00008d38 &lt;+24&gt;:	bx	lrEnd of assembler dump.

根据 Arm 架构的函数调用特性，寄存器 lr 保存着 key3() 函数的返回地址，因此 key3() 函数的返回值为 0x00008d80。
将三个返回值相加，计算出 key 值为 0x0001A770，得到 flag 信息。
