#include &lt;stdio.h&gt;#include &lt;fcntl.h&gt;#define PW_LEN 10#define XORKEY 1void xor(char* s, int len)&#123;	int i;	for(i=0; i&lt;len; i++)&#123;		s[i] ^= XORKEY;	&#125;&#125;int main(int argc, char* argv[])&#123;		int fd;	if(fd=open(&quot;/home/mistake/password&quot;,O_RDONLY,0400) &lt; 0)&#123;		printf(&quot;can&#x27;t open password %d\n&quot;, fd);		return 0;	&#125;	printf(&quot;do not bruteforce...\n&quot;);	sleep(time(0)%20);	char pw_buf[PW_LEN+1];	int len;	if(!(len=read(fd,pw_buf,PW_LEN) &gt; 0))&#123;		printf(&quot;read error\n&quot;);		close(fd);		return 0;			&#125;	char pw_buf2[PW_LEN+1];	printf(&quot;input password : &quot;);	scanf(&quot;%10s&quot;, pw_buf2);	// xor your input	xor(pw_buf2, 10);	if(!strncmp(pw_buf, pw_buf2, PW_LEN))&#123;		printf(&quot;Password OK\n&quot;);		setregid(getegid(), getegid());		system(&quot;/bin/cat flag\n&quot;);	&#125;	else&#123;		printf(&quot;Wrong Password\n&quot;);	&#125;	close(fd);	return 0;&#125;

由于在 C 语言中，运算符 = 低于运算符 &lt; 的优先级，所以 fd 保存的是 open(&quot;/home/mistake/password&quot;,O_RDONLY,0400) &lt; 0 的比较结果，而不是 /home/mistake/password 的文件指针。
因此 read() 函数实际是从 stdin 中读取数据。这将使得 pw_buf 和 pw_buf2 的内容均可控，从而可以通过校验，得到 flag 信息。
